1	const DEEPSEEK_BASE = "https://api.deepseek.com/v1";
2	const MODEL = "deepseek-v4-flash";
3	
4	export interface AiCallOptions {
5	  messages: { role: "system" | "user" | "assistant"; content: string }[];
6	  temperature?: number;
7	  timeout?: number;
8	}
9	
10	export async function callDeepSeek<T = unknown>(
11	  options: AiCallOptions,
12	): Promise<T> {
13	  const { messages, temperature = 0.3, timeout = 5000 } = options;
14	
15	  const controller = new AbortController();
16	  const timer = setTimeout(() => controller.abort(), timeout);
17	
18	  try {
19	    const res = await fetch(`${DEEPSEEK_BASE}/chat/completions`, {
20	      method: "POST",
21	      headers: {
22	        "Content-Type": "application/json",
23	        Authorization: `Bearer ${process.env.AI_API_KEY}`,
24	      },
25	      body: JSON.stringify({
26	        model: MODEL,
27	        messages,
28	        temperature,
29	        response_format: { type: "json_object" },
30	      }),
31	      signal: controller.signal,
32	    });
33	
34	    if (!res.ok) {
35	      throw new Error(`DeepSeek API error: ${res.status}`);
36	    }
37	
38	    const data = (await res.json()) as {
39	      choices: { message: { content: string } }[];
40	    };
41	    const content = data.choices?.[0]?.message?.content;
42	    if (!content) throw new Error("Empty response from DeepSeek");
43	
44	    return JSON.parse(content) as T;
45	  } catch (e) {
46	    if (e instanceof DOMException && e.name === "AbortError") {
47	      throw new Error("DeepSeek API timeout");
48	    }
49	    throw e;
50	  } finally {
51	    clearTimeout(timer);
52	  }
53	}
