1	import { SignJWT, jwtVerify } from "jose";
2	
3	const CONFIRMATION_SECRET = new TextEncoder().encode(
4	  process.env.AUTH_SECRET + ":confirmation",
5	);
6	
7	export interface ConfirmationPayload {
8	  userId: string;
9	  action: "create_repair" | "create_apply";
10	  params: Record<string, unknown>;
11	  exp: number;
12	}
13	
14	const usedTokens = new Set<string>();
15	
16	export async function generateConfirmationToken(
17	  payload: Omit<ConfirmationPayload, "exp">,
18	): Promise<string> {
19	  const exp = Math.floor(Date.now() / 1000) + 300;
20	  const token = await new SignJWT({ ...payload, exp })
21	    .setProtectedHeader({ alg: "HS256" })
22	    .sign(CONFIRMATION_SECRET);
23	  return token;
24	}
25	
26	export async function verifyConfirmationToken(
27	  token: string,
28	  userId: string,
29	): Promise<ConfirmationPayload | null> {
30	  try {
31	    const { payload } = await jwtVerify(token, CONFIRMATION_SECRET, {
32	      algorithms: ["HS256"],
33	    });
34	
35	    if (payload.userId !== userId) return null;
36	
37	    // One-time use: check blacklist and mark used
38	    if (usedTokens.has(token)) return null;
39	    usedTokens.add(token);
40	
41	    return payload as unknown as ConfirmationPayload;
42	  } catch {
43	    return null;
44	  }
45	}
