"use client";

/**
 * AI 助手对话 (所有角色)
 * 接入 /api/ai/chat 真实 API
 */

import { useState, useRef, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/lib/auth-context";
import { apiFetch } from "@/lib/api-client";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Bot, Send, User, AlertTriangle } from "lucide-react";

interface ChatMessage {
  role: "user" | "assistant";
  content: string;
}

interface ChatResponse {
  reply: string;
  needConfirmation?: boolean;
  pendingAction?: {
    type: string;
    description: string;
  };
  confirmationToken?: string;
  fallback?: boolean;
}

interface ConfirmationDialogState {
  open: boolean;
  token: string;
  description: string;
  actionType: string;
}

export default function ChatPage() {
  const { user } = useAuth();
  const router = useRouter();

  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: "assistant",
      content:
        "你好！我是 IT 资产助手，可以帮你查询资产信息、保修状态、工单进度，也可以引导你进行设备申领或报修。请问有什么可以帮你的？",
    },
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [confirmDialog, setConfirmDialog] = useState<ConfirmationDialogState>({
    open: false,
    token: "",
    description: "",
    actionType: "",
  });
  const bottomRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to latest message
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isLoading]);

  const buildHistory = (msgs: ChatMessage[]): ChatMessage[] => {
    // Exclude the initial greeting from history
    return msgs.filter((_, i) => i > 0);
  };

  const handleSend = useCallback(async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: ChatMessage = {
      role: "user",
      content: input.trim(),
    };

    setInput("");
    setError(null);
    setMessages((prev) => [...prev, userMessage]);
    setIsLoading(true);

    try {
      const updatedMessages = [...messages, userMessage];
      const history = buildHistory(updatedMessages);

      const data = await apiFetch<ChatResponse>("/api/ai/chat", {
        method: "POST",
        body: JSON.stringify({
          message: userMessage.content,
          history: history.map((m) => ({
            role: m.role,
            content: m.content,
          })),
        }),
      });

      const assistantMessage: ChatMessage = {
        role: "assistant",
        content: data.reply,
      };

      // Note if fallback was used
      if (data.fallback) {
        assistantMessage.content =
          data.reply + "\n\n> *AI 助手暂时不可用，以上为离线回复*";
      }

      setMessages((prev) => [...prev, assistantMessage]);

      // Show confirmation dialog if needed
      if (data.needConfirmation && data.pendingAction && data.confirmationToken) {
        setConfirmDialog({
          open: true,
          token: data.confirmationToken,
          description: data.pendingAction.description,
          actionType: data.pendingAction.type,
        });
      }
    } catch (err) {
      const errorMsg =
        err instanceof Error ? err.message : "网络请求失败，请稍后重试";
      setError(errorMsg);
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "抱歉，我暂时无法处理你的请求。请检查网络连接后重试。",
        },
      ]);
    } finally {
      setIsLoading(false);
    }
  }, [input, isLoading, messages]);

  const handleConfirm = () => {
    const { actionType } = confirmDialog;
    setConfirmDialog({ open: false, token: "", description: "", actionType: "" });

    // Navigate based on action type
    switch (actionType) {
      case "create_apply":
        router.push("/apply");
        break;
      case "create_repair":
        router.push("/tickets");
        break;
      default:
        // Generic navigation for unknown action types
        router.push("/tickets");
    }
  };

  const handleCancel = () => {
    setConfirmDialog({ open: false, token: "", description: "", actionType: "" });
    setMessages((prev) => [
      ...prev,
      {
        role: "assistant",
        content: "好的，已取消该操作。还有什么我可以帮你的吗？",
      },
    ]);
  };

  return (
    <div className="max-w-3xl mx-auto h-[calc(100vh-8rem)] flex flex-col">
      <div className="mb-4">
        <h1 className="text-2xl font-bold tracking-tight">AI 助手</h1>
        <p className="text-muted-foreground mt-1">智能 IT 资产助手，帮你查询和管理设备</p>
      </div>

      {/* Error banner */}
      {error && (
        <div className="mb-3 p-3 rounded-lg bg-destructive/10 text-destructive text-sm flex items-center gap-2">
          <AlertTriangle className="w-4 h-4 flex-shrink-0" />
          <span>{error}</span>
          <button
            onClick={() => setError(null)}
            className="ml-auto text-destructive/70 hover:text-destructive"
          >
            x
          </button>
        </div>
      )}

      {/* Chat Messages */}
      <Card className="flex-1 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {messages.map((msg, i) => (
            <div
              key={i}
              className={`flex gap-3 ${msg.role === "user" ? "justify-end" : ""}`}
            >
              {msg.role === "assistant" && (
                <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center flex-shrink-0">
                  <Bot className="w-4 h-4 text-primary-foreground" />
                </div>
              )}
              <div
                className={`max-w-[75%] ${msg.role === "user" ? "order-1" : ""}`}
              >
                <div
                  className={`p-3 rounded-xl text-sm whitespace-pre-wrap ${
                    msg.role === "user"
                      ? "bg-primary text-primary-foreground rounded-tr-sm"
                      : "bg-muted rounded-tl-sm"
                  }`}
                >
                  {msg.content}
                </div>
              </div>
              {msg.role === "user" && (
                <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center flex-shrink-0">
                  <User className="w-4 h-4 text-muted-foreground" />
                </div>
              )}
            </div>
          ))}

          {/* Typing indicator */}
          {isLoading && (
            <div className="flex gap-3">
              <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center flex-shrink-0">
                <Bot className="w-4 h-4 text-primary-foreground" />
              </div>
              <div className="bg-muted p-3 rounded-xl rounded-tl-sm">
                <div className="flex gap-1.5">
                  <span className="w-2 h-2 rounded-full bg-muted-foreground/40 animate-bounce" />
                  <span
                    className="w-2 h-2 rounded-full bg-muted-foreground/40 animate-bounce"
                    style={{ animationDelay: "0.15s" }}
                  />
                  <span
                    className="w-2 h-2 rounded-full bg-muted-foreground/40 animate-bounce"
                    style={{ animationDelay: "0.3s" }}
                  />
                </div>
              </div>
            </div>
          )}

          <div ref={bottomRef} />
        </div>

        {/* Input area */}
        <div className="border-t p-4">
          <div className="flex gap-2">
            <Input
              placeholder="输入你的问题，如：我的保修信息、我要报修笔记本..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSend()}
              disabled={isLoading}
              className="flex-1"
            />
            <Button
              onClick={handleSend}
              disabled={!input.trim() || isLoading}
            >
              <Send className="w-4 h-4" />
            </Button>
          </div>
          <p className="text-xs text-muted-foreground mt-2">
            提示：你可以查询资产信息、保修状态、工单进度，或让 AI 引导你完成报修/申领
          </p>
        </div>
      </Card>

      {/* Confirmation Dialog */}
      <Dialog
        open={confirmDialog.open}
        onOpenChange={(open) => {
          if (!open) handleCancel();
        }}
      >
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertTriangle className="w-5 h-5 text-warning" />
              确认操作
            </DialogTitle>
            <DialogDescription>即将执行以下操作：</DialogDescription>
          </DialogHeader>
          <div className="p-3 rounded-lg bg-muted text-sm">
            {confirmDialog.description}
          </div>
          <div className="flex justify-end gap-3 mt-4">
            <Button variant="outline" onClick={handleCancel}>
              取消
            </Button>
            <Button onClick={handleConfirm}>确认执行</Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

