19	export default function StatsPage() {
20	  const [habits, setHabits] = useState<HabitWithLogs[]>([]);
21	  const [loading, setLoading] = useState(true);
22	  const [range, setRange] = useState<"week" | "month">("week");
23	
24	  useEffect(() => { fetchStats(); }, [range]);
25	
26	  async function fetchStats() {
27	    const data = await apiFetch(`/api/stats?range=${range}`);
28	    setHabits(data.habits || []);
29	    setLoading(false);
30	  }
31	
32	  if (loading) return <div className="flex items-center justify-center h-64 text-muted-foreground">加载中...</div>;
33	
34	  const totalChecks = habits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
35	  const totalPossible = habits.length * (range === "week" ? 7 : 30);
36	  const overallRate = totalPossible > 0 ? Math.round((totalChecks / totalPossible) * 100) : 0;
37	
38	  // Domain completion rates
39	  const domainStats = PRESET_DOMAINS.map((d) => {
40	    const domainHabits = habits.filter((h) => h.domainId === d.name);
41	    const completed = domainHabits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
42	    const possible = domainHabits.length * (range === "week" ? 7 : 30);
43	    return { name: d.name, icon: d.icon, rate: possible > 0 ? Math.round((completed / possible) * 100) : 0, color: d.color };
44	  }).filter((d) => d.rate > 0);
45	
46	  // Weekly bar data
47	  const days = range === "week" ? 7 : 30;
48	  const barData = Array.from({ length: days }, (_, i) => {
49	    const d = new Date();
50	    d.setDate(d.getDate() - (days - 1 - i));
51	    const dateStr = d.toISOString().split("T")[0];
52	    const completed = habits.filter((h) => h.logs.some((l) => l.date === dateStr && l.completed)).length;
53	    return {
54	      date: d.toLocaleDateString("zh-CN", { month: "short", day: "numeric" }),
55	      completed,
56	      total: habits.length,
57	    };
58	  });
59	
60	  const streakDays = calculateStreak(habits);
61	
62	  return (
63	    <div className="max-w-2xl mx-auto space-y-6">
64	      <div>
65	        <h1 className="text-3xl font-bold tracking-tight">数据统计</h1>
66	        <p className="text-sm text-muted-foreground mt-1">看见进步，持续精进</p>
67	      </div>
68	
69	      {/* Range Toggle */}
70	      <div className="flex gap-2">
71	        <button onClick={() => setRange("week")} className={`px-4 py-2 rounded-xl text-sm font-medium ${range === "week" ? "bg-primary text-primary-foreground" : "bg-muted"}`}>本周</button>
72	        <button onClick={() => setRange("month")} className={`px-4 py-2 rounded-xl text-sm font-medium ${range === "month" ? "bg-primary text-primary-foreground" : "bg-muted"}`}>本月</button>
73	      </div>
74	
75	      {/* Key Metrics */}
76	      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
77	        <div className="bg-card rounded-xl border p-4 text-center">
78	          <p className="text-3xl font-bold">{overallRate}%</p>
79	          <p className="text-xs text-muted-foreground mt-1">总完成率</p>
80	        </div>
81	        <div className="bg-card rounded-xl border p-4 text-center">
82	          <p className="text-3xl font-bold">{totalChecks}</p>
83	          <p className="text-xs text-muted-foreground mt-1">总打卡数</p>
84	        </div>
85	        <div className="bg-card rounded-xl border p-4 text-center">
86	          <p className="text-3xl font-bold">{streakDays}</p>
87	          <p className="text-xs text-muted-foreground mt-1">连续天数</p>
88	        </div>
89	        <div className="bg-card rounded-xl border p-4 text-center">
90	          <p className="text-3xl font-bold">{habits.length}</p>
91	          <p className="text-xs text-muted-foreground mt-1">活跃习惯</p>
92	        </div>
93	      </div>
94	
95	      {/* Bar Chart */}
96	      <div className="bg-card rounded-2xl border p-6">
97	        <h2 className="font-semibold mb-4">每日完成趋势</h2>
98	        <ResponsiveContainer width="100%" height={200}>
99	          <BarChart data={barData}>
100	            <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
101	            <XAxis dataKey="date" tick={{ fontSize: 12, fill: "var(--muted-fg)" }} />
102	            <YAxis allowDecimals={false} tick={{ fontSize: 12, fill: "var(--muted-fg)" }} />
103	            <Tooltip />
104	            <Bar dataKey="completed" fill="var(--primary)" radius={[4, 4, 0, 0]} />
105	          </BarChart>
106	        </ResponsiveContainer>
107	      </div>
108	
109	      {/* Radar Chart */}
110	      {domainStats.length > 0 && (
111	        <div className="bg-card rounded-2xl border p-6">
112	          <h2 className="font-semibold mb-4">领域均衡度</h2>
113	          <ResponsiveContainer width="100%" height={280}>
114	            <RadarChart data={domainStats}>
115	              <PolarGrid stroke="var(--border)" />
116	              <PolarAngleAxis dataKey="name" tick={{ fontSize: 12, fill: "var(--muted-fg)" }} />
117	              <PolarRadiusAxis angle={90} domain={[0, 100]} tick={{ fontSize: 10 }} />
118	              <Radar dataKey="rate" stroke="var(--primary)" fill="var(--primary)" fillOpacity={0.15} />
119	            </RadarChart>
120	          </ResponsiveContainer>
121	        </div>
122	      )}
123	    </div>
124	  );
125	}
126	
127	function calculateStreak(habits: HabitWithLogs[]): number {
128	  if (habits.length === 0) return 0;
129	  const allDates = new Set<string>();
130	  habits.forEach((h) => h.logs.filter((l) => l.completed).forEach((l) => allDates.add(l.date)));
131	  const sorted = [...allDates].sort().reverse();
132	  let streak = 0;
133	  const today = new Date(getToday());
134	  for (let i = 0; i < sorted.length; i++) {
135	    const expected = new Date(today);
136	    expected.setDate(expected.getDate() - i);
137	    if (sorted[i] === expected.toISOString().split("T")[0]) streak++;
138	    else break;
139	  }
140	  return streak;
141	}
