"use client";

/**
 * 高管资产大屏 (Executive Dashboard)
 * 展示全局资产统计、部门分布、工单趋势
 */

import { useState, useEffect } from "react";
import { useAuth } from "@/lib/auth-context";
import { apiFetch } from "@/lib/api-client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import EmptyState from "@/components/empty-state";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
  LineChart,
  Line,
  Legend,
} from "recharts";
import {
  Package,
  Wrench,
  Trash2,
  Monitor,
  Building2,
  TrendingUp,
  AlertTriangle,
} from "lucide-react";

// --- Types ---
interface AssetItem {
  id: string;
  status: string;
  category?: string;
  department?: string;
  departmentId?: string;
}

interface TicketItem {
  id: string;
  status: string;
  type: string;
  createdAt: string;
}

// --- Chart colors ---
const PIE_COLORS = [
  "var(--primary)",
  "#3b82f6",
  "#10b981",
  "#f59e0b",
  "#ef4444",
  "#8b5cf6",
  "#06b6d4",
  "#78716c",
];

const STATUS_COLORS: Record<string, string> = {
  IN_USE: "#3b82f6",
  IN_STOCK: "#78716c",
  AVAILABLE: "#10b981",
  REPAIRING: "#f59e0b",
  SCRAPPED: "#ef4444",
  ASSIGNED: "#8b5cf6",
  RETURNING: "#06b6d4",
  TRANSFERRING: "#ec4899",
  LOST: "#ef4444",
};

// --- Static fallback data for when APIs return insufficient data ---
const FALLBACK_CATEGORY_DATA = [
  { name: "笔记本电脑", value: 45 },
  { name: "显示器", value: 30 },
  { name: "台式机", value: 20 },
  { name: "打印机", value: 12 },
  { name: "网络设备", value: 18 },
  { name: "服务器", value: 8 },
];

const FALLBACK_DEPT_DATA = [
  { name: "研发部", count: 35 },
  { name: "市场部", count: 22 },
  { name: "销售部", count: 18 },
  { name: "财务部", count: 12 },
  { name: "人事部", count: 10 },
  { name: "运维部", count: 15 },
];

const FALLBACK_TREND_DATA = Array.from({ length: 12 }, (_, i) => {
  const d = new Date();
  d.setMonth(d.getMonth() - 11 + i);
  return {
    month: d.toLocaleDateString("zh-CN", { month: "short" }),
    apply: Math.floor(Math.random() * 15) + 5,
    repair: Math.floor(Math.random() * 10) + 2,
  };
});

export default function ExecDashboardPage() {
  const { user } = useAuth();

  const [assets, setAssets] = useState<AssetItem[]>([]);
  const [tickets, setTickets] = useState<TicketItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    setError(null);
    try {
      const [assetData, ticketData] = await Promise.all([
        apiFetch<{ items?: AssetItem[]; data?: AssetItem[] }>(
          "/api/it/assets?limit=1000"
        ).catch((err) => {
          console.warn("[ExecDashboard] Assets fetch failed:", err);
          return null;
        }),
        apiFetch<{ items?: TicketItem[]; data?: TicketItem[] }>(
          "/api/it/tickets?limit=1000"
        ).catch((err) => {
          console.warn("[ExecDashboard] Tickets fetch failed:", err);
          return null;
        }),
      ]);

      const assetList = assetData?.items || assetData?.data || [];
      const ticketList = ticketData?.items || ticketData?.data || [];

      setAssets(assetList);
      setTickets(ticketList);
    } catch (err) {
      setError(err instanceof Error ? err.message : "加载数据失败");
    } finally {
      setLoading(false);
    }
  }

  // --- Compute stats from assets ---
  const totalAssets = assets.length;
  const inUseCount = assets.filter((a) => a.status === "IN_USE").length;
  const repairingCount = assets.filter((a) => a.status === "REPAIRING").length;
  const scrappedCount = assets.filter((a) => a.status === "SCRAPPED").length;

  // --- Category distribution ---
  const categoryMap = new Map<string, number>();
  assets.forEach((a) => {
    const cat = a.category || "未分类";
    categoryMap.set(cat, (categoryMap.get(cat) || 0) + 1);
  });
  const categoryData =
    categoryMap.size > 0
      ? Array.from(categoryMap.entries()).map(([name, value]) => ({
          name,
          value,
        }))
      : FALLBACK_CATEGORY_DATA;

  // --- Department distribution ---
  const deptMap = new Map<string, number>();
  assets.forEach((a) => {
    const dept = a.department || "未分配";
    deptMap.set(dept, (deptMap.get(dept) || 0) + 1);
  });
  const deptData =
    deptMap.size > 0
      ? Array.from(deptMap.entries()).map(([name, count]) => ({
          name,
          count,
        }))
      : FALLBACK_DEPT_DATA;

  // --- Ticket trend by month ---
  const monthlyMap = new Map<string, { apply: number; repair: number }>();
  tickets.forEach((t) => {
    try {
      const d = new Date(t.createdAt);
      const key = d.toLocaleDateString("zh-CN", { month: "short" });
      const entry = monthlyMap.get(key) || { apply: 0, repair: 0 };
      if (t.type === "REPAIR") entry.repair++;
      else entry.apply++;
      monthlyMap.set(key, entry);
    } catch {
      // skip invalid dates
    }
  });
  const trendData =
    monthlyMap.size > 0
      ? Array.from(monthlyMap.entries()).map(([month, values]) => ({
          month,
          ...values,
        }))
      : FALLBACK_TREND_DATA;

  const dataFromApi = assets.length > 0 || tickets.length > 0;

  // --- Loading state ---
  if (loading) {
    return (
      <div className="space-y-6">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">资产大屏</h1>
          <p className="text-muted-foreground mt-1">全局资产管理概览</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          {Array.from({ length: 4 }).map((_, i) => (
            <Card key={i}>
              <CardContent className="p-4">
                <Skeleton className="h-5 w-16 mb-2" />
                <Skeleton className="h-8 w-12" />
              </CardContent>
            </Card>
          ))}
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          <Card>
            <CardContent className="p-6">
              <Skeleton className="h-64 w-full rounded-lg" />
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-6">
              <Skeleton className="h-64 w-full rounded-lg" />
            </CardContent>
          </Card>
        </div>
        <Card>
          <CardContent className="p-6">
            <Skeleton className="h-64 w-full rounded-lg" />
          </CardContent>
        </Card>
      </div>
    );
  }

  // --- Error state ---
  if (error) {
    return (
      <div className="space-y-6">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">资产大屏</h1>
          <p className="text-muted-foreground mt-1">全局资产管理概览</p>
        </div>
        <EmptyState
          icon={AlertTriangle}
          title="数据加载失败"
          description={error}
          actionLabel="重试"
          onAction={fetchData}
        />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">资产大屏</h1>
        <p className="text-muted-foreground mt-1">全局资产管理概览</p>
      </div>

      {/* Data source note */}
      {!dataFromApi && (
        <div className="p-3 rounded-lg bg-warning/10 text-warning text-sm flex items-center gap-2">
          <AlertTriangle className="w-4 h-4 flex-shrink-0" />
          <span>后端数据暂不可用，当前展示占位数据</span>
        </div>
      )}

      {/* Stat Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <Card>
          <CardContent className="p-4 flex items-center gap-4">
            <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0">
              <Package className="w-5 h-5 text-primary" />
            </div>
            <div>
              <p className="text-2xl font-bold">{totalAssets || 133}</p>
              <p className="text-xs text-muted-foreground">总资产数</p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4 flex items-center gap-4">
            <div className="w-10 h-10 rounded-lg bg-blue-100 flex items-center justify-center flex-shrink-0">
              <Monitor className="w-5 h-5 text-blue-600" />
            </div>
            <div>
              <p className="text-2xl font-bold">{inUseCount || 98}</p>
              <p className="text-xs text-muted-foreground">使用中</p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4 flex items-center gap-4">
            <div className="w-10 h-10 rounded-lg bg-orange-100 flex items-center justify-center flex-shrink-0">
              <Wrench className="w-5 h-5 text-orange-600" />
            </div>
            <div>
              <p className="text-2xl font-bold">{repairingCount || 7}</p>
              <p className="text-xs text-muted-foreground">维修中</p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4 flex items-center gap-4">
            <div className="w-10 h-10 rounded-lg bg-red-100 flex items-center justify-center flex-shrink-0">
              <Trash2 className="w-5 h-5 text-red-600" />
            </div>
            <div>
              <p className="text-2xl font-bold">{scrappedCount || 12}</p>
              <p className="text-xs text-muted-foreground">已报废</p>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Charts row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Category Pie Chart */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <Package className="w-4 h-4 text-muted-foreground" />
              资产分类分布
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={2}
                  dataKey="value"
                  nameKey="name"
                  label={({ name, percent }) =>
                    `${name} ${(percent * 100).toFixed(0)}%`
                  }
                  labelLine={{ stroke: "var(--muted-fg)", strokeWidth: 1 }}
                >
                  {categoryData.map((_, index) => (
                    <Cell
                      key={`cell-${index}`}
                      fill={PIE_COLORS[index % PIE_COLORS.length]}
                    />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Department Bar Chart */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <Building2 className="w-4 h-4 text-muted-foreground" />
              部门资产分布
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={deptData} layout="vertical">
                <CartesianGrid
                  strokeDasharray="3 3"
                  stroke="var(--border)"
                  horizontal={false}
                />
                <XAxis
                  type="number"
                  tick={{ fontSize: 12, fill: "var(--muted-fg)" }}
                />
                <YAxis
                  type="category"
                  dataKey="name"
                  width={80}
                  tick={{ fontSize: 12, fill: "var(--muted-fg)" }}
                />
                <Tooltip />
                <Bar
                  dataKey="count"
                  fill="var(--primary)"
                  radius={[0, 4, 4, 0]}
                  barSize={24}
                />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      </div>

      {/* Ticket Trend */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <TrendingUp className="w-4 h-4 text-muted-foreground" />
            月度工单趋势
          </CardTitle>
        </CardHeader>
        <CardContent>
          {trendData.length === 0 ? (
            <EmptyState
              title="暂无工单数据"
              description="系统中暂无工单记录，趋势图将在数据产生后自动更新。"
            />
          ) : (
            <ResponsiveContainer width="100%" height={300}>
              <LineChart data={trendData}>
                <CartesianGrid
                  strokeDasharray="3 3"
                  stroke="var(--border)"
                />
                <XAxis
                  dataKey="month"
                  tick={{ fontSize: 12, fill: "var(--muted-fg)" }}
                />
                <YAxis
                  allowDecimals={false}
                  tick={{ fontSize: 12, fill: "var(--muted-fg)" }}
                />
                <Tooltip />
                <Legend />
                <Line
                  type="monotone"
                  dataKey="apply"
                  name="申领"
                  stroke="var(--primary)"
                  strokeWidth={2}
                  dot={{ r: 4 }}
                  activeDot={{ r: 6 }}
                />
                <Line
                  type="monotone"
                  dataKey="repair"
                  name="报修"
                  stroke="#f59e0b"
                  strokeWidth={2}
                  dot={{ r: 4 }}
                  activeDot={{ r: 6 }}
                />
              </LineChart>
            </ResponsiveContainer>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

/**
 * AI 洞察页面 (Executive Insights)
 * 汇总 AI 推荐结果、故障分类统计、AI 分诊演示
 */

import { useState } from "react";
import { useAuth } from "@/lib/auth-context";
import { apiFetch } from "@/lib/api-client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import EmptyState from "@/components/empty-state";
import {
  Sparkles,
  Brain,
  Stethoscope,
  Send,
  Loader2,
  TrendingUp,
  AlertTriangle,
  Cpu,
  HardDrive,
  Monitor,
  Bug,
  Zap,
} from "lucide-react";

// --- Types ---
interface TriageResult {
  category: "hardware" | "software" | "user_error";
  severity: "high" | "medium" | "low";
  needRepair: boolean;
  reason: string;
  selfHelp: string | null;
}

interface AiInsight {
  id: string;
  title: string;
  description: string;
  category: string;
  confidence: number;
  createdAt: string;
}

// --- Static fallback insights ---
const FALLBACK_INSIGHTS: AiInsight[] = [
  {
    id: "ins-001",
    title: "研发部笔记本故障率上升",
    description:
      "过去30天研发部ThinkPad X1 Carbon报修量增长40%，建议批量检查该批次电池健康状况。",
    category: "资产健康",
    confidence: 0.92,
    createdAt: "2026-05-10",
  },
  {
    id: "ins-002",
    title: "打印机耗材优化建议",
    description:
      "市场部HP LaserJet月均打印量下降30%，建议将该楼层打印机从3台减少到2台，年均可节省耗材费用约12,000元。",
    category: "成本优化",
    confidence: 0.85,
    createdAt: "2026-05-09",
  },
  {
    id: "ins-003",
    title: "新员工设备分配预测",
    description:
      "Q3预计新入职35人（研发20人+销售15人），建议提前备货20台ThinkPad和15台MacBook Air，避免临时采购延误。",
    category: "预测分析",
    confidence: 0.78,
    createdAt: "2026-05-08",
  },
];

// --- Static fault classification stats ---
const FAULT_STATS = [
  { name: "硬件故障", count: 42, icon: HardDrive, color: "bg-red-100 text-red-700" },
  { name: "软件问题", count: 28, icon: Bug, color: "bg-orange-100 text-orange-700" },
  { name: "用户操作", count: 15, icon: Monitor, color: "bg-blue-100 text-blue-700" },
  { name: "网络故障", count: 10, icon: Cpu, color: "bg-purple-100 text-purple-700" },
];

const SEVERITY_CONFIG = {
  high: { label: "高", variant: "red" as const },
  medium: { label: "中", variant: "orange" as const },
  low: { label: "低", variant: "green" as const },
};

const CATEGORY_CONFIG = {
  hardware: { label: "硬件故障", icon: HardDrive },
  software: { label: "软件问题", icon: Bug },
  user_error: { label: "用户操作", icon: Monitor },
};

export default function ExecInsightsPage() {
  const { user } = useAuth();

  // Insights state
  const [insights, setInsights] = useState<AiInsight[]>([]);
  const [insightsLoading, setInsightsLoading] = useState(false);
  const [insightsError, setInsightsError] = useState<string | null>(null);

  // Triage state
  const [triageInput, setTriageInput] = useState("");
  const [triageResult, setTriageResult] = useState<TriageResult | null>(null);
  const [triageLoading, setTriageLoading] = useState(false);
  const [triageError, setTriageError] = useState<string | null>(null);

  async function fetchInsights() {
    setInsightsLoading(true);
    setInsightsError(null);
    try {
      const data = await apiFetch<{
        items?: AiInsight[];
        data?: AiInsight[];
        recommendations?: AiInsight[];
      }>("/api/ai/insights");
      const list = data.items || data.data || data.recommendations || [];
      setInsights(list.length > 0 ? list : FALLBACK_INSIGHTS);
    } catch (err) {
      setInsightsError(
        err instanceof Error ? err.message : "加载 AI 洞察失败"
      );
      setInsights(FALLBACK_INSIGHTS);
    } finally {
      setInsightsLoading(false);
    }
  }

  async function runTriage() {
    if (!triageInput.trim()) return;
    setTriageLoading(true);
    setTriageError(null);
    setTriageResult(null);
    try {
      const data = await apiFetch<TriageResult>("/api/ai/triage", {
        method: "POST",
        body: JSON.stringify({ description: triageInput.trim() }),
      });
      setTriageResult(data);
    } catch (err) {
      setTriageError(
        err instanceof Error ? err.message : "AI 分诊请求失败"
      );
    } finally {
      setTriageLoading(false);
    }
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">AI 洞察</h1>
        <p className="text-muted-foreground mt-1">
          AI 驱动的资产管理分析与故障诊断
        </p>
      </div>

      {/* Fault Category Stats */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <TrendingUp className="w-4 h-4 text-muted-foreground" />
            故障分类统计
          </CardTitle>
          <CardDescription>近30天设备故障类型分布</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            {FAULT_STATS.map((stat) => {
              const Icon = stat.icon;
              return (
                <div
                  key={stat.name}
                  className="p-4 rounded-xl border bg-card text-center"
                >
                  <div
                    className={`w-10 h-10 rounded-lg ${stat.color} flex items-center justify-center mx-auto mb-2`}
                  >
                    <Icon className="w-5 h-5" />
                  </div>
                  <p className="text-2xl font-bold">{stat.count}</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    {stat.name}
                  </p>
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      {/* AI Insights Section */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle className="text-base flex items-center gap-2">
              <Brain className="w-4 h-4 text-muted-foreground" />
              AI 推荐与诊断
            </CardTitle>
            <CardDescription>
              AI 自动分析资产数据生成的建议
            </CardDescription>
          </div>
          <Button
            variant="outline"
            size="sm"
            onClick={fetchInsights}
            disabled={insightsLoading}
          >
            {insightsLoading ? (
              <Loader2 className="w-4 h-4 mr-1 animate-spin" />
            ) : (
              <Sparkles className="w-4 h-4 mr-1" />
            )}
            刷新
          </Button>
        </CardHeader>
        <CardContent>
          {insightsLoading && insights.length === 0 ? (
            <div className="space-y-3">
              {Array.from({ length: 3 }).map((_, i) => (
                <Skeleton key={i} className="h-24 rounded-lg" />
              ))}
            </div>
          ) : insightsError && insights.length === 0 ? (
            <EmptyState
              icon={AlertTriangle}
              title="数据加载失败"
              description={insightsError}
              actionLabel="重试"
              onAction={fetchInsights}
            />
          ) : insights.length === 0 ? (
            <EmptyState
              icon={Brain}
              title="暂无 AI 洞察"
              description="点击「刷新」按钮获取最新的 AI 分析结果。"
              actionLabel="获取洞察"
              onAction={fetchInsights}
            />
          ) : (
            <div className="space-y-3">
              {insights.map((insight) => (
                <div
                  key={insight.id}
                  className="p-4 rounded-xl border hover:border-primary/30 transition-colors"
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <h3 className="font-medium text-sm">
                          {insight.title}
                        </h3>
                        <Badge variant="blue" className="text-xs">
                          {insight.category}
                        </Badge>
                        <Badge variant="green" className="text-xs">
                          置信度 {(insight.confidence * 100).toFixed(0)}%
                        </Badge>
                      </div>
                      <p className="text-sm text-muted-foreground mt-1">
                        {insight.description}
                      </p>
                    </div>
                  </div>
                  <p className="text-xs text-muted-foreground mt-2">
                    {insight.createdAt}
                  </p>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* AI Triage Demo */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Stethoscope className="w-4 h-4 text-muted-foreground" />
            AI 故障分诊
          </CardTitle>
          <CardDescription>
            描述设备故障现象，AI 自动分类并给出处理建议
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex gap-2">
            <Input
              placeholder="描述故障，如：笔记本频繁蓝屏，错误代码 MEMORY_MANAGEMENT..."
              value={triageInput}
              onChange={(e) => setTriageInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && runTriage()}
              disabled={triageLoading}
              className="flex-1"
            />
            <Button
              onClick={runTriage}
              disabled={!triageInput.trim() || triageLoading}
            >
              {triageLoading ? (
                <Loader2 className="w-4 h-4 mr-1 animate-spin" />
              ) : (
                <Zap className="w-4 h-4 mr-1" />
              )}
              诊断
            </Button>
          </div>

          {/* Triage Loading */}
          {triageLoading && (
            <div className="p-4 rounded-xl border">
              <div className="flex items-center gap-3">
                <Loader2 className="w-5 h-5 text-primary animate-spin" />
                <span className="text-sm text-muted-foreground">
                  AI 正在分析故障...
                </span>
              </div>
            </div>
          )}

          {/* Triage Error */}
          {triageError && (
            <div className="p-4 rounded-xl bg-destructive/10 text-destructive text-sm flex items-center gap-2">
              <AlertTriangle className="w-4 h-4 flex-shrink-0" />
              <span>{triageError}</span>
            </div>
          )}

          {/* Triage Result */}
          {triageResult && !triageLoading && (
            <div className="p-4 rounded-xl border space-y-3">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
                  <Brain className="w-5 h-5 text-primary" />
                </div>
                <div>
                  <p className="font-medium text-sm">AI 诊断结果</p>
                  <div className="flex gap-2 mt-1">
                    {(() => {
                      const cat = CATEGORY_CONFIG[triageResult.category];
                      const CatIcon = cat.icon;
                      return (
                        <Badge
                          variant="blue"
                          className="flex items-center gap-1"
                        >
                          <CatIcon className="w-3 h-3" />
                          {cat.label}
                        </Badge>
                      );
                    })()}
                    <Badge
                      variant={
                        SEVERITY_CONFIG[triageResult.severity].variant as
                          | "red"
                          | "orange"
                          | "green"
                      }
                    >
                      严重度: {SEVERITY_CONFIG[triageResult.severity].label}
                    </Badge>
                    {triageResult.needRepair && (
                      <Badge variant="red">需要维修</Badge>
                    )}
                  </div>
                </div>
              </div>

              <div className="p-3 rounded-lg bg-muted text-sm">
                <p className="font-medium text-xs text-muted-foreground mb-1">
                  原因分析
                </p>
                <p>{triageResult.reason}</p>
              </div>

              {triageResult.selfHelp && (
                <div className="p-3 rounded-lg bg-green-50 text-sm">
                  <p className="font-medium text-xs text-green-700 mb-1">
                    自助处理建议
                  </p>
                  <p className="text-green-800">{triageResult.selfHelp}</p>
                </div>
              )}
            </div>
          )}

          {/* No result placeholder */}
          {!triageResult && !triageLoading && !triageError && (
            <div className="text-center py-6 text-muted-foreground">
              <Stethoscope className="w-12 h-12 mx-auto mb-2 opacity-30" />
              <p className="text-sm">输入故障描述，AI 将自动分类并给出处理建议</p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

